#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Modernized Climate Data Analysis Script (Python 3).

Replaces the broken legacy Python 2.7 implementation in
``climate_analyzer/analyze_climate.py``.
"""
from __future__ import annotations

import configparser
from pathlib import Path

import numpy as np
import pandas as pd

BASE_DIR = Path(__file__).resolve().parent
DATA_FILE = BASE_DIR / "climate_analyzer" / "sample_data" / "climate_data.csv"
CONFIG_FILE = BASE_DIR / "climate_analyzer" / "config.ini"


class ClimateAnalyzer:
    """Load climate data and compute per-station temperature statistics."""

    def __init__(self, config_path: Path = CONFIG_FILE) -> None:
        self.config = configparser.ConfigParser()
        config_path = Path(config_path)
        if config_path.exists():
            self.config.read(config_path, encoding="utf-8")

    def load_temperature_data(self, filename: Path) -> pd.DataFrame:
        """Read the CSV file with pandas using UTF-8 encoding."""
        return pd.read_csv(
            Path(filename),
            encoding="utf-8",
            parse_dates=["date"],
        )

    def station_mean_temperatures(self, df: pd.DataFrame) -> pd.Series:
        """Return the mean temperature per station id."""
        return df.groupby("station_id")["temperature"].mean()

    def calculate_anomalies(self, temperature_series: pd.Series) -> np.ndarray:
        """Calculate temperature anomalies relative to the series mean."""
        values = np.asarray(temperature_series, dtype=np.float64)
        return values - np.mean(values)

    def run_analysis(self) -> pd.Series:
        """Main analysis pipeline."""
        print("Starting climate analysis...")

        data = self.load_temperature_data(DATA_FILE)
        means = self.station_mean_temperatures(data)

        for station_id, mean_temp in means.items():
            print(f"Station {station_id} mean temperature: {mean_temp:.1f}°C")

        print("Analysis completed successfully!")
        return means


def main() -> None:
    analyzer = ClimateAnalyzer()
    analyzer.run_analysis()


if __name__ == "__main__":
    main()
